            // Assert
            resultado.Should().NotBeNull();
            // Deve usar operador BETWEEN
            resultado.Value.where.Should().Contain($"[{DBLivroCaixaDicInfo.PTabelaNome}].{DBLivroCaixaDicInfo.QuemAtu} BETWEEN @{DBLivroCaixaDicInfo.QuemAtu} AND @{DBLivroCaixaDicInfo.QuemAtu}_end");
